import io.grpc.*;
import io.grpc.stub.*;
import java.io.*;
import java.util.concurrent.*;
import java.util.logging.*;

public class FileTransferService {
    private static final Logger logger = Logger.getLogger(FileTransferService.class.getName());
    private Server server;

    public void start(int port) throws IOException {
        server = ServerBuilder.forPort(port)
                .addService(new FileTransferImpl())
                .build()
                .start();
        logger.info("Server started on port " + port);
        Runtime.getRuntime().addShutdownHook(new Thread(() -> {
            System.err.println("Shutting down gRPC server");
            server.shutdown();
            try {
                server.awaitTermination();
            } catch (InterruptedException e) {
                e.printStackTrace();
            }
        }));
    }

    public void blockUntilShutdown() throws InterruptedException {
        if (server != null) {
            server.awaitTermination();
        }
    }

    static class FileTransferImpl extends FileTransferGrpc.FileTransferImplBase {
        @Override
        public StreamObserver<UploadRequest> uploadFile(StreamObserver<UploadResponse> responseObserver) {
            return new StreamObserver<UploadRequest>() {
                private FileOutputStream fileOutputStream;
                private String fileName;
                private long totalBytes = 0;

                @Override
                public void onNext(UploadRequest request) {
                    try {
                        if (fileName == null) {
                            fileName = request.getFileName();
                            fileOutputStream = new FileOutputStream(fileName);
                        }
                        fileOutputStream.write(request.getData().toByteArray());
                        totalBytes += request.getData().size();
                    } catch (IOException e) {
                        logger.severe("Error writing file: " + e.getMessage());
                        responseObserver.onError(e);
                    }
                }

                @Override
                public void onError(Throwable t) {
                    logger.severe("Upload error: " + t.getMessage());
                    try {
                        if (fileOutputStream != null) {
                            fileOutputStream.close();
                        }
                    } catch (IOException e) {
                        logger.severe("Error closing file: " + e.getMessage());
                    }
                    responseObserver.onError(t);
                }

                @Override
                public void onCompleted() {
                    try {
                        if (fileOutputStream != null) {
                            fileOutputStream.close();
                        }
                        UploadResponse response = UploadResponse.newBuilder()
                                .setFileName(fileName)
                                .setTotalBytes(totalBytes)
                                .setSuccess(true)
                                .build();
                        responseObserver.onNext(response);
                        responseObserver.onCompleted();
                    } catch (IOException e) {
                        logger.severe("Error completing upload: " + e.getMessage());
                        responseObserver.onError(e);
                    }
                }
            };
        }

        @Override
        public void downloadFile(DownloadRequest request, StreamObserver<DownloadResponse> responseObserver) {
            try {
                File file = new File(request.getFileName());
                if (!file.exists()) {
                    responseObserver.onError(Status.NOT_FOUND.withDescription("File not found").asException());
                    return;
                }
                FileInputStream fileInputStream = new FileInputStream(file);
                byte[] buffer = new byte[1024];
                int bytesRead;
                while ((bytesRead = fileInputStream.read(buffer)) != -1) {
                    DownloadResponse response = DownloadResponse.newBuilder()
                            .setData(ByteString.copyFrom(buffer, 0, bytesRead))
                            .build();
                    responseObserver.onNext(response);
                }
                fileInputStream.close();
                responseObserver.onCompleted();
            } catch (IOException e) {
                logger.severe("Error downloading file: " + e.getMessage());
                responseObserver.onError(e);
            }
        }

        @Override
        public StreamObserver<TransferRequest> transferData(StreamObserver<TransferResponse> responseObserver) {
            return new StreamObserver<TransferRequest>() {
                private long totalBytes = 0;
                private int messageCount = 0;

                @Override
                public void onNext(TransferRequest request) {
                    try {
                        totalBytes += request.getData().size();
                        messageCount++;
                        TransferResponse response = TransferResponse.newBuilder()
                                .setReceivedBytes(totalBytes)
                                .setMessageCount(messageCount)
                                .build();
                        responseObserver.onNext(response);
                    } catch (Exception e) {
                        logger.severe("Error processing transfer: " + e.getMessage());
                        responseObserver.onError(e);
                    }
                }

                @Override
                public void onError(Throwable t) {
                    logger.severe("Transfer error: " + t.getMessage());
                    responseObserver.onError(t);
                }

                @Override
                public void onCompleted() {
                    TransferResponse response = TransferResponse.newBuilder()
                            .setReceivedBytes(totalBytes)
                            .setMessageCount(messageCount)
                            .setCompleted(true)
                            .build();
                    responseObserver.onNext(response);
                    responseObserver.onCompleted();
                }
            };
        }
    }

    public static void main(String[] args) throws IOException, InterruptedException {
        FileTransferService service = new FileTransferService();
        service.start(8080);
        service.blockUntilShutdown();
    }
}